     5→//! Column table formatting for JJK output
     6→//!
     7→//! Provides structured column layout to eliminate magic numbers/strings
     8→//! from formatted output operations. Single source of truth for headers,
     9→//! widths, and alignment.
    10→
    11→/// Gap between columns
    12→pub const JJRP_COLUMN_GAP: usize = 2;
    13→
    14→/// Minimum column width
    15→pub const JJRP_MIN_WIDTH: usize = 5;
    16→
    17→/// Column alignment
    18→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    19→pub enum jjrp_Align {
    20→    Left,
    21→    Right,
    22→}
    23→
    24→/// Column definition
    25→#[derive(Debug, Clone)]
    26→pub struct jjrp_Column {
    27→    /// Header text (single source of truth)
    28→    pub header: &'static str,
    29→    /// Minimum width (defaults to header.len())
    30→    pub min_width: usize,
    31→    /// Alignment
    32→    pub align: jjrp_Align,
    33→}
    34→
    35→impl jjrp_Column {
    36→    /// Create a new column with default min_width from header
    37→    pub fn new(header: &'static str, align: jjrp_Align) -> Self {
    38→        Self {
    39→            header,
    40→            min_width: header.len().max(JJRP_MIN_WIDTH),
    41→            align,
    42→        }
    43→    }
    44→
    45→    /// Create a new column with explicit min_width
    46→    pub fn with_width(header: &'static str, min_width: usize, align: jjrp_Align) -> Self {
    47→        Self {
    48→            header,
    49→            min_width: min_width.max(JJRP_MIN_WIDTH),
    50→            align,
    51→        }
    52→    }
    53→}
    54→
    55→/// Table with columns and computed widths
    56→pub struct jjrp_Table {
    57→    columns: Vec<jjrp_Column>,
    58→    widths: Vec<usize>,
    59→}
    60→
    61→impl jjrp_Table {
    62→    /// Create a new table with the given columns
    63→    pub fn jjrp_new(columns: Vec<jjrp_Column>) -> Self {
    64→        let widths = columns.iter().map(|c| c.min_width).collect();
    65→        Self { columns, widths }
    66→    }
    67→
    68→    /// Update column widths based on a data row
    69→    pub fn jjrp_measure(&mut self, row: &[&str]) {
    70→        for (i, value) in row.iter().enumerate() {
    71→            if i < self.widths.len() {
    72→                self.widths[i] = self.widths[i].max(value.len());
    73→            }
    74→        }
    75→    }
    76→
    77→    /// Print the header row
    78→    pub fn jjrp_print_header(&self) {
    79→        let mut parts = Vec::new();
    80→        for (i, col) in self.columns.iter().enumerate() {
    81→            let width = self.widths[i];
    82→            let formatted = match col.align {
    83→                jjrp_Align::Left => format!("{:<width$}", col.header, width = width),
    84→                jjrp_Align::Right => format!("{:>width$}", col.header, width = width),
    85→            };
    86→            parts.push(formatted);
    87→        }
    88→        println!("{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
    89→    }
    90→
    91→    /// Print a separator line using computed widths
    92→    pub fn jjrp_print_separator(&self) {
    93→        let mut parts = Vec::new();
    94→        for width in &self.widths {
    95→            parts.push("-".repeat(*width));
    96→        }
    97→        println!("{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
    98→    }
    99→
   100→    /// Print a data row
   101→    pub fn jjrp_print_row(&self, values: &[&str]) {
   102→        let mut parts = Vec::new();
   103→        for (i, value) in values.iter().enumerate() {
   104→            if i < self.columns.len() {
   105→                let width = self.widths[i];
   106→                let col = &self.columns[i];
   107→                let formatted = match col.align {
   108→                    jjrp_Align::Left => format!("{:<width$}", value, width = width),
   109→                    jjrp_Align::Right => format!("{:>width$}", value, width = width),
   110→                };
   111→                parts.push(formatted);
   112→            }
   113→        }
   114→        println!("{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
   115→    }
   116→}
   117→
   118→#[cfg(test)]
   119→mod tests {
   120→    use super::*;
   121→
   122→    #[test]
   123→    fn test_column_new() {
   124→        let col = jjrp_Column::new("Test", jjrp_Align::Left);
   125→        assert_eq!(col.header, "Test");
   126→        assert_eq!(col.min_width, JJRP_MIN_WIDTH);
   127→        assert_eq!(col.align, jjrp_Align::Left);
   128→    }
   129→
   130→    #[test]
   131→    fn test_column_with_width() {
   132→        let col = jjrp_Column::with_width("ID", 10, jjrp_Align::Right);
   133→        assert_eq!(col.header, "ID");
   134→        assert_eq!(col.min_width, 10);
   135→        assert_eq!(col.align, jjrp_Align::Right);
   136→    }
   137→
   138→    #[test]
   139→    fn test_table_measure() {
   140→        let columns = vec![
   141→            jjrp_Column::new("Name", jjrp_Align::Left),
   142→            jjrp_Column::new("ID", jjrp_Align::Right),
   143→        ];
   144→        let mut table = jjrp_Table::jjrp_new(columns);
   145→
   146→        // Initial widths are min_width
   147→        assert_eq!(table.widths[0], JJRP_MIN_WIDTH);
   148→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH);
   149→
   150→        // Measure a row with longer values
   151→        table.jjrp_measure(&["Very Long Name", "12345"]);
   152→        assert_eq!(table.widths[0], 14); // "Very Long Name".len()
   153→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH); // Still min because "12345" is shorter
   154→    }
   155→
   156→    #[test]
   157→    fn test_table_output() {
   158→        let columns = vec![
   159→            jjrp_Column::new("₣Fire", jjrp_Align::Left),
   160→            jjrp_Column::new("Silks", jjrp_Align::Left),
   161→            jjrp_Column::new("Count", jjrp_Align::Right),
   162→        ];
   163→        let mut table = jjrp_Table::jjrp_new(columns);
   164→
   165→        // Measure some data
   166→        table.jjrp_measure(&["₣AB", "test-heat", "42"]);
   167→        table.jjrp_measure(&["₣CD", "another-heat-name", "100"]);
   168→
   169→        // These would print to stdout in actual usage
   170→        // Just verify they don't panic
   171→        table.jjrp_print_header();
   172→        table.jjrp_print_separator();
   173→        table.jjrp_print_row(&["₣AB", "test-heat", "42"]);
   174→        table.jjrp_print_row(&["₣CD", "another-heat-name", "100"]);
   175→    }
   176→}
