     5→//! Query operations for Gallops JSON
     6→//!
     7→//! Implements read operations: muster, saddle, parade, retire.
     8→//! All operations read from Gallops JSON and optionally paddock files.
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    13→use crate::jjrs_steeplechase::{jjrs_SteeplechaseEntry, jjrs_get_entries, jjrs_ReinArgs};
    14→use serde::Serialize;
    15→use std::fs;
    16→
    17→/// Resolve the default heat (first racing heat) when no target is specified
    18→pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    19→    for (heat_key, heat) in &gallops.heats {
    20→        if heat.status == HeatStatus::Racing {
    21→            return Ok(heat_key.clone());
    22→        }
    23→    }
    24→    Err("No racing heats found".to_string())
    25→}
    26→
    27→// ============================================================================
    28→// Muster - List all Heats with summary information
    29→// ============================================================================
    30→
    31→/// Arguments for muster command
    32→#[derive(Debug)]
    33→pub struct jjrq_MusterArgs {
    34→    pub file: std::path::PathBuf,
    35→    pub status: Option<String>,
    36→}
    37→
    38→/// Run the muster command - list Heats as TSV
    39→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    40→    let gallops = match Gallops::jjrg_load(&args.file) {
    41→        Ok(g) => g,
    42→        Err(e) => {
    43→            eprintln!("jjx_muster: error: {}", e);
    44→            return 1;
    45→        }
    46→    };
    47→
    48→    // Collect heats with status info for sorting
    49→    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
    50→
    51→    // Apply status filter if specified
    52→    if let Some(ref filter_status) = args.status {
    53→        let filter_lowercase = filter_status.to_lowercase();
    54→        heats_by_status.retain(|(_, heat)| {
    55→            let heat_status_str = match heat.status {
    56→                HeatStatus::Racing => "racing",
    57→                HeatStatus::Stabled => "stabled",
    58→                HeatStatus::Retired => "retired",
    59→            };
    60→            heat_status_str == filter_lowercase
    61→        });
    62→    }
    63→
    64→    // Sort: racing first, then stabled, then retired
    65→    heats_by_status.sort_by(|a, b| {
    66→        let a_status_order = match a.1.status {
    67→            HeatStatus::Racing => 0,
    68→            HeatStatus::Stabled => 1,
    69→            HeatStatus::Retired => 2,
    70→        };
    71→        let b_status_order = match b.1.status {
    72→            HeatStatus::Racing => 0,
    73→            HeatStatus::Stabled => 1,
    74→            HeatStatus::Retired => 2,
    75→        };
    76→        a_status_order.cmp(&b_status_order)
    77→    });
    78→
    79→    // Calculate max silks width for column alignment
    80→    let max_silks_len = heats_by_status.iter()
    81→        .map(|(_, heat)| heat.silks.len())
    82→        .max()
    83→        .unwrap_or(20)
    84→        .max(20);
    85→
    86→    // Print header (avoid # which markdown interprets as heading)
    87→    println!("{:<5}  {:<width$}  {:<7}  {:>4}  {:>5}", "Fire", "Silks", "Status", "Done", "Total", width = max_silks_len);
    88→    println!("{}", "-".repeat(5 + 2 + max_silks_len + 2 + 7 + 2 + 4 + 2 + 5));
    89→
    90→    for (key, heat) in heats_by_status {
    91→        // Count paces where state != Abandoned
    92→        let defined_count = heat.paces.values().filter(|pace| {
    93→            if let Some(tack) = pace.tacks.first() {
    94→                tack.state != PaceState::Abandoned
    95→            } else {
    96→                true
    97→            }
    98→        }).count();
    99→
   100→        // Count paces where state == Complete
   101→        let completed_count = heat.paces.values().filter(|pace| {
   102→            if let Some(tack) = pace.tacks.first() {
   103→                tack.state == PaceState::Complete
   104→            } else {
   105→                false
   106→            }
   107→        }).count();
   108→
   109→        let status_str = match heat.status {
   110→            HeatStatus::Racing => "racing",
   111→            HeatStatus::Stabled => "stabled",
   112→            HeatStatus::Retired => "retired",
   113→        };
   114→
   115→        println!("{:<5}  {:<width$}  {:<7}  {:>4}  {:>5}", key, heat.silks, status_str, completed_count, defined_count, width = max_silks_len);
   116→    }
   117→
   118→    0
   119→}
   120→
   121→// ============================================================================
   122→// Saddle - Return context needed to saddle up on a Heat
   123→// ============================================================================
   124→
   125→/// Arguments for saddle command
   126→#[derive(Debug)]
   127→pub struct jjrq_SaddleArgs {
   128→    pub file: std::path::PathBuf,
   129→    pub firemark: Firemark,
   130→}
   131→
   132→/// Output structure for saddle command
   133→#[derive(Serialize)]
   134→pub(crate) struct zjjrq_SaddleOutput {
   135→    pub(crate) heat_silks: String,
   136→    pub(crate) paddock_file: String,
   137→    pub(crate) paddock_content: String,
   138→    #[serde(skip_serializing_if = "Option::is_none")]
   139→    pub(crate) pace_coronet: Option<String>,
   140→    #[serde(skip_serializing_if = "Option::is_none")]
   141→    pub(crate) pace_silks: Option<String>,
   142→    #[serde(skip_serializing_if = "Option::is_none")]
   143→    pub(crate) pace_state: Option<String>,
   144→    #[serde(skip_serializing_if = "Option::is_none")]
   145→    pub(crate) spec: Option<String>,
   146→    #[serde(skip_serializing_if = "Option::is_none")]
   147→    pub(crate) direction: Option<String>,
   148→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
   149→}
   150→
   151→/// Run the saddle command - return Heat context
   152→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   153→    let gallops = match Gallops::jjrg_load(&args.file) {
   154→        Ok(g) => g,
   155→        Err(e) => {
   156→            eprintln!("jjx_saddle: error: {}", e);
   157→            return 1;
   158→        }
   159→    };
   160→
   161→    let heat_key = args.firemark.jjrf_display();
   162→    let heat = match gallops.heats.get(&heat_key) {
   163→        Some(h) => h,
   164→        None => {
   165→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   166→            return 1;
   167→        }
   168→    };
   169→
   170→    // Check if heat is stabled (cannot saddle stabled heat)
   171→    if heat.status == HeatStatus::Stabled {
   172→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   173→        return 1;
   174→    }
   175→
   176→    // Read paddock file content
   177→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   178→        Ok(content) => content,
   179→        Err(e) => {
   180→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   181→            return 1;
   182→        }
   183→    };
   184→
   185→    // Get recent steeplechase entries
   186→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   187→        firemark: args.firemark.jjrf_as_str().to_string(),
   188→        limit: 10,
   189→    }).unwrap_or_default();
   190→
   191→    // Find first actionable pace (rough or bridled)
   192→    let mut output = zjjrq_SaddleOutput {
   193→        heat_silks: heat.silks.clone(),
   194→        paddock_file: heat.paddock_file.clone(),
   195→        paddock_content,
   196→        pace_coronet: None,
   197→        pace_silks: None,
   198→        pace_state: None,
   199→        spec: None,
   200→        direction: None,
   201→        recent_work,
   202→    };
   203→
   204→    for coronet_key in &heat.order {
   205→        if let Some(pace) = heat.paces.get(coronet_key) {
   206→            if let Some(tack) = pace.tacks.first() {
   207→                match tack.state {
   208→                    PaceState::Rough | PaceState::Bridled => {
   209→                        output.pace_coronet = Some(coronet_key.clone());
   210→                        output.pace_silks = Some(tack.silks.clone());
   211→                        output.pace_state = Some(match tack.state {
   212→                            PaceState::Rough => "rough".to_string(),
   213→                            PaceState::Bridled => "bridled".to_string(),
   214→                            _ => unreachable!(),
   215→                        });
   216→                        output.spec = Some(tack.text.clone());
   217→                        if tack.state == PaceState::Bridled {
   218→                            output.direction = tack.direction.clone();
   219→                        }
   220→                        break;
   221→                    }
   222→                    _ => continue,
   223→                }
   224→            }
   225→        }
   226→    }
   227→
   228→    // Output JSON
   229→    match serde_json::to_string_pretty(&output) {
   230→        Ok(json) => {
   231→            println!("{}", json);
   232→            0
   233→        }
   234→        Err(e) => {
   235→            eprintln!("jjx_saddle: error serializing output: {}", e);
   236→            1
   237→        }
   238→    }
   239→}
   240→
   241→// ============================================================================
   242→// Parade - Display comprehensive Heat status for project review
   243→// ============================================================================
   244→
   245→/// Arguments for parade command
   246→#[derive(Debug)]
   247→pub struct jjrq_ParadeArgs {
   248→    pub file: std::path::PathBuf,
   249→    pub target: String,
   250→    pub full: bool,
   251→    pub remaining: bool,
   252→}
   253→
   254→/// Run the parade command - display comprehensive Heat status
   255→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   256→    let gallops = match Gallops::jjrg_load(&args.file) {
   257→        Ok(g) => g,
   258→        Err(e) => {
   259→            eprintln!("jjx_parade: error: {}", e);
   260→            return 1;
   261→        }
   262→    };
   263→
   264→    // Determine target type by length
   265→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   266→
   267→    if target_str.len() == 5 {
   268→        // Coronet - pace view
   269→        let coronet = match Coronet::jjrf_parse(&args.target) {
   270→            Ok(c) => c,
   271→            Err(e) => {
   272→                eprintln!("jjx_parade: error: {}", e);
   273→                return 1;
   274→            }
   275→        };
   276→
   277→        // Extract parent firemark
   278→        let firemark = coronet.jjrf_parent_firemark();
   279→        let heat_key = firemark.jjrf_display();
   280→        let heat = match gallops.heats.get(&heat_key) {
   281→            Some(h) => h,
   282→            None => {
   283→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   284→                return 1;
   285→            }
   286→        };
   287→
   288→        // Find pace
   289→        let coronet_key = coronet.jjrf_display();
   290→        let pace = match heat.paces.get(&coronet_key) {
   291→            Some(p) => p,
   292→            None => {
   293→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   294→                return 1;
   295→            }
   296→        };
   297→
   298→        // Display tack history - iterate in reverse order (oldest first)
   299→        if !pace.tacks.is_empty() {
   300→            // Print header with current state from tacks[0]
   301→            let current_tack = &pace.tacks[0];
   302→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   303→            println!("Heat: {}", heat_key);
   304→            println!();
   305→
   306→            // Iterate tacks in reverse order (oldest first)
   307→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   308→                let state_str = zjjrq_pace_state_str(&tack.state);
   309→                let commit_str = if tack.commit == "0000000" {
   310→                    "(no commit)".to_string()
   311→                } else {
   312→                    tack.commit.clone()
   313→                };
   314→
   315→                println!("[{}] {} ({})", index, state_str, commit_str);
   316→                println!("    Silks: {}", tack.silks);
   317→                if let Some(ref direction) = tack.direction {
   318→                    println!("    Direction: {}", direction);
   319→                }
   320→                println!();
   321→                // Indent spec text
   322→                for line in tack.text.lines() {
   323→                    println!("    {}", line);
   324→                }
   325→                println!();
   326→            }
   327→        }
   328→    } else if target_str.len() == 2 {
   329→        // Firemark - heat view
   330→        let firemark = match Firemark::jjrf_parse(&args.target) {
   331→            Ok(fm) => fm,
   332→            Err(e) => {
   333→                eprintln!("jjx_parade: error: {}", e);
   334→                return 1;
   335→            }
   336→        };
   337→
   338→        let heat_key = firemark.jjrf_display();
   339→        let heat = match gallops.heats.get(&heat_key) {
   340→            Some(h) => h,
   341→            None => {
   342→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   343→                return 1;
   344→            }
   345→        };
   346→
   347→        if args.full {
   348→            // Full view: paddock + all specs
   349→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   350→                Ok(content) => content,
   351→                Err(e) => {
   352→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   353→                    return 1;
   354→                }
   355→            };
   356→
   357→            let status_str = match heat.status {
   358→                HeatStatus::Racing => "racing",
   359→                HeatStatus::Stabled => "stabled",
   360→                HeatStatus::Retired => "retired",
   361→            };
   362→
   363→            println!("Heat: {} ({})", heat.silks, heat_key);
   364→            println!("Status: {}", status_str);
   365→            println!("Created: {}", heat.creation_time);
   366→            println!();
   367→            println!("## Paddock");
   368→            println!();
   369→            println!("{}", paddock_content);
   370→            println!();
   371→            println!("## Paces");
   372→            println!();
   373→
   374→            for coronet_key in &heat.order {
   375→                if let Some(pace) = heat.paces.get(coronet_key) {
   376→                    if let Some(tack) = pace.tacks.first() {
   377→                        // Skip complete/abandoned if --remaining
   378→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   379→                            continue;
   380→                        }
   381→                        let state_str = zjjrq_pace_state_str(&tack.state);
   382→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   383→                        println!();
   384→                        println!("{}", tack.text);
   385→                        if let Some(ref direction) = tack.direction {
   386→                            println!();
   387→                            println!("**Direction:** {}", direction);
   388→                        }
